import{_ as i,o as s,c as l,ag as t}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"版本控制","description":"","frontmatter":{},"headers":[],"relativePath":"zh/tools/version-control.md","filePath":"zh/tools/version-control.md"}'),e={name:"zh/tools/version-control.md"};function n(o,a,h,r,p,d){return s(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="版本控制" tabindex="-1">版本控制 <a class="header-anchor" href="#版本控制" aria-label="Permalink to &quot;版本控制&quot;">​</a></h1><h2 id="为什么需要版本控制" tabindex="-1">为什么需要版本控制？ <a class="header-anchor" href="#为什么需要版本控制" aria-label="Permalink to &quot;为什么需要版本控制？&quot;">​</a></h2><p>版本控制是现代软件开发的基础。它支持：</p><ul><li>跟踪代码随时间的变化</li><li>团队间的协作</li><li>代码审查和质量把控</li><li>版本回退能力</li><li>发布管理</li></ul><h2 id="git-基础" tabindex="-1">Git 基础 <a class="header-anchor" href="#git-基础" aria-label="Permalink to &quot;Git 基础&quot;">​</a></h2><p>Git 是业界标准的分布式版本控制系统，被开源社区和企业广泛使用。</p><h3 id="关键概念" tabindex="-1">关键概念 <a class="header-anchor" href="#关键概念" aria-label="Permalink to &quot;关键概念&quot;">​</a></h3><p><strong>仓库</strong>：包含所有代码和历史的项目 <strong>提交</strong>：包含元数据的代码快照 <strong>分支</strong>：平行开发线 <strong>远程</strong>：中央化仓库（GitHub、GitLab） <strong>合并</strong>：来自不同分支的更改组合</p><h3 id="常见-git-工作流" tabindex="-1">常见 Git 工作流 <a class="header-anchor" href="#常见-git-工作流" aria-label="Permalink to &quot;常见 Git 工作流&quot;">​</a></h3><p><strong>特性分支工作流</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature/new-auth-system</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 进行更改</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;实现 JWT 认证&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature/new-auth-system</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 创建拉取请求</span></span></code></pre></div><p><strong>Git Flow</strong></p><ul><li><code>main</code>（生产就绪）</li><li><code>develop</code>（集成分支）</li><li><code>feature/*</code>（新特性）</li><li><code>hotfix/*</code>（生产补丁）</li><li><code>release/*</code>（发布准备）</li></ul><p><strong>基于主干的开发</strong></p><ul><li>单一主分支（<code>main</code>）</li><li>短期特性分支（&lt; 1 天）</li><li>持续集成</li><li>使用特性标志表示不完整工作</li></ul><h2 id="github" tabindex="-1">GitHub <a class="header-anchor" href="#github" aria-label="Permalink to &quot;GitHub&quot;">​</a></h2><p>世界领先的协作软件开发平台。</p><h3 id="github-工作流" tabindex="-1">GitHub 工作流 <a class="header-anchor" href="#github-工作流" aria-label="Permalink to &quot;GitHub 工作流&quot;">​</a></h3><p><strong>拉取请求（PRs）</strong></p><ul><li>代码审查机制</li><li>自动化检查和测试</li><li>讨论和批准工作流</li><li>合并策略（压缩、变基、合并提交）</li></ul><p><strong>GitHub Actions</strong></p><ul><li>原生 CI/CD 平台</li><li>自动化测试和部署</li><li>定时工作流</li><li>社区维护的 Actions</li></ul><p><strong>GitHub Issues</strong></p><ul><li>错误跟踪</li><li>功能请求</li><li>项目规划</li><li>讨论线程</li></ul><h3 id="github-最佳实践" tabindex="-1">GitHub 最佳实践 <a class="header-anchor" href="#github-最佳实践" aria-label="Permalink to &quot;GitHub 最佳实践&quot;">​</a></h3><ul><li>要求分支保护规则</li><li>合并前强制代码审查</li><li>对所有 PR 运行自动化测试</li><li>使用语义化提交消息</li><li>使用版本号标记发布</li></ul><h2 id="分支策略" tabindex="-1">分支策略 <a class="header-anchor" href="#分支策略" aria-label="Permalink to &quot;分支策略&quot;">​</a></h2><h3 id="特性分支" tabindex="-1">特性分支 <a class="header-anchor" href="#特性分支" aria-label="Permalink to &quot;特性分支&quot;">​</a></h3><ul><li>每个特性一个分支</li><li>短期（1-3 天）</li><li>合并前进行自动化测试</li></ul><h3 id="环境分支" tabindex="-1">环境分支 <a class="header-anchor" href="#环境分支" aria-label="Permalink to &quot;环境分支&quot;">​</a></h3><ul><li><code>main</code> → 生产</li><li><code>staging</code> → 预生产</li><li><code>develop</code> → 集成</li></ul><h3 id="发布分支" tabindex="-1">发布分支 <a class="header-anchor" href="#发布分支" aria-label="Permalink to &quot;发布分支&quot;">​</a></h3><ul><li><code>release/v1.2.0</code> 用于发布准备</li><li>使用版本标记修复</li><li>自动版本号碰撞</li></ul><h2 id="提交消息指南" tabindex="-1">提交消息指南 <a class="header-anchor" href="#提交消息指南" aria-label="Permalink to &quot;提交消息指南&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;类型&gt;(&lt;范围&gt;): &lt;主题&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;正文&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;页脚&gt;</span></span></code></pre></div><p><strong>类型</strong>：feat、fix、docs、style、refactor、test、chore <strong>示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat(auth): 添加 JWT 令牌刷新端点</span></span>
<span class="line"><span></span></span>
<span class="line"><span>实现自动令牌刷新以改进用户体验</span></span>
<span class="line"><span>并减少会话超时。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>修复 #123</span></span></code></pre></div><h2 id="代码审查最佳实践" tabindex="-1">代码审查最佳实践 <a class="header-anchor" href="#代码审查最佳实践" aria-label="Permalink to &quot;代码审查最佳实践&quot;">​</a></h2><ol><li><strong>及时审查</strong>：24 小时内审查</li><li><strong>建设性反馈</strong>：专注于代码，而不是个人</li><li><strong>清晰批准</strong>：区分批准和建议</li><li><strong>自动化检查</strong>：让工具强制执行标准</li><li><strong>记录决策</strong>：解释为什么，而不仅仅是什么</li></ol><h2 id="高级主题" tabindex="-1">高级主题 <a class="header-anchor" href="#高级主题" aria-label="Permalink to &quot;高级主题&quot;">​</a></h2><h3 id="git-钩子" tabindex="-1">Git 钩子 <a class="header-anchor" href="#git-钩子" aria-label="Permalink to &quot;Git 钩子&quot;">​</a></h3><p>自动化检查提交/推送前</p><ul><li><code>pre-commit</code>：lint、格式检查</li><li><code>commit-msg</code>：强制提交消息格式</li><li><code>pre-push</code>：本地运行测试</li></ul><h3 id="语义化版本控制" tabindex="-1">语义化版本控制 <a class="header-anchor" href="#语义化版本控制" aria-label="Permalink to &quot;语义化版本控制&quot;">​</a></h3><ul><li>主.次.补（例如 1.2.3）</li><li>主：不兼容的 API 更改</li><li>次：向后兼容的特性</li><li>补：错误修复</li></ul><h3 id="提交压缩" tabindex="-1">提交压缩 <a class="header-anchor" href="#提交压缩" aria-label="Permalink to &quot;提交压缩&quot;">​</a></h3><p>在合并前组合多个提交以保持历史整洁</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rebase</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD~3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 压缩最后 3 个提交</span></span></code></pre></div>`,48)])])}const g=i(e,[["render",n]]);export{u as __pageData,g as default};
